parameters.jsCode:
const webhook = $('Webhook – Meeting Notes').first().json;
const ai = $input.first().json;

let parsed = ai.message?.content ?? ai.content ?? ai;

if (typeof parsed === 'string') {
  try {
    parsed = JSON.parse(parsed);
  } catch (error) {
    parsed = {
      summary: parsed,
      key_decisions: [],
      action_items: [],
      participants_mentioned: [],
      follow_ups: [],
    };
  }
}

const actionItems = Array.isArray(parsed.action_items) ? parsed.action_items : [];

return [
  {
    json: {
      transcript: webhook.transcript,
      user_id: webhook.user_id,
      user_name: webhook.user_name,
      user_email: webhook.user_email,
      company_id: webhook.company_id,
      duration_seconds: webhook.duration_seconds,
      stopped_reason: webhook.stopped_reason,
      recorded_at: webhook.recorded_at,
      meeting_summary: parsed.summary ?? '',
      key_decisions: parsed.key_decisions ?? [],
      action_items: actionItems,
      action_items_count: actionItems.length,
      participants_mentioned: parsed.participants_mentioned ?? [],
      follow_ups: parsed.follow_ups ?? [],
      processed_at: new Date().toISOString(),
    },
  },
];

